#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        long long total = 0;
        while (A != B) {
            if (A > B) {
                int eat = (A + 1) / 2; // ceil(A/2)
                total += eat;
                A = A / 2; // floor(A/2)
            } else {
                int eat = (B + 1) / 2;
                total += eat;
                B = B / 2;
            }
        }
        printf("%lld\n", total);
    }
    return 0;
}

