#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it))
        B = int(next(it))
        total = 0
        while A != B:
            if A > B:
                eat = (A + 1) // 2
                total += eat
                A //= 2
            else:
                eat = (B + 1) // 2
                total += eat
                B //= 2
        out.append(str(total))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

